import React, { useEffect, useState } from "react";
import axios from "../api"; // axios instance

const SearchForm = () => {
  const [districts, setDistricts] = useState([]);
  const [talukas, setTalukas] = useState([]);
  const [villages, setVillages] = useState([]);
  const [formData, setFormData] = useState({
    district: "",
    taluka: "",
    village: "",
  });

  // Fetch districts on load
  useEffect(() => {
    axios
      .get("/districts/")
      .then((res) => setDistricts(res.data))
      .catch((err) => console.error("Error fetching districts:", err));
  }, []);

  // Fetch talukas when district changes
  useEffect(() => {
    if (formData.district) {
      axios
        .get(`/talukas/${formData.district}/`)
        .then((res) => setTalukas(res.data))
        .catch((err) => console.error("Error fetching talukas:", err));
      setFormData((prev) => ({ ...prev, taluka: "", village: "" }));
      setVillages([]);
    }
  }, [formData.district]);

  // Fetch villages when taluka changes
  useEffect(() => {
    if (formData.taluka) {
      axios
        .get(`/villages/${formData.taluka}/`)
        .then((res) => setVillages(res.data))
        .catch((err) => console.error("Error fetching villages:", err));
      setFormData((prev) => ({ ...prev, village: "" }));
    }
  }, [formData.taluka]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Search Data:", formData);
    // Add axios POST request if needed
  };

  return (
    <form onSubmit={handleSubmit}>
      {/* District Dropdown */}
      <label>District:</label>
      <select
        name="district"
        value={formData.district}
        onChange={handleChange}
      >
        <option value="">--निवडा--</option>
        {districts.map((d) => (
          <option key={d.id} value={d.id}>
            {d.name}
          </option>
        ))}
      </select>

      {/* Taluka Dropdown */}
      <label>Taluka:</label>
      <select
        name="taluka"
        value={formData.taluka}
        onChange={handleChange}
        disabled={!formData.district}
      >
        <option value="">--निवडा--</option>
        {talukas.map((t) => (
          <option key={t.id} value={t.id}>
            {t.name}
          </option>
        ))}
      </select>

      {/* Village Dropdown */}
      <label>Village:</label>
      <select
        name="village"
        value={formData.village}
        onChange={handleChange}
        disabled={!formData.taluka}
      >
        <option value="">--निवडा--</option>
        {villages.map((v) => (
          <option key={v.id} value={v.id}>
            {v.name}
          </option>
        ))}
      </select>

      <button type="submit">Search</button>
    </form>
  );
};

export default SearchForm;
